schema:
[
  {
    "field": "invoice_number",
    "type": "string",
    "sensitive": false,
    "constraints": "Unique identifier"
  },
  {
    "field": "issue_date",
    "type": "date",
    "sensitive": false,
    "constraints": "Format MM/DD/YYYY"
  },
  {
    "field": "seller",
    "type": "object",
    "sensitive": false,
    "constraints": "Contains entity details"
  },
  {
    "field": "seller_name",
    "type": "string",
    "sensitive": true,
    "constraints": "Part of seller"
  },
  {
    "field": "seller_address",
    "type": "string",
    "sensitive": true,
    "constraints": "Part of seller"
  },
  {
    "field": "seller_tax_id",
    "type": "string",
    "sensitive": true,
    "constraints": "Part of seller"
  },
  {
    "field": "client",
    "type": "object",
    "sensitive": false,
    "constraints": "Contains entity details"
  },
  {
    "field": "client_name",
    "type": "string",
    "sensitive": true,
    "constraints": "Part of client"
  },
  {
    "field": "client_address",
    "type": "string",
    "sensitive": true,
    "constraints": "Part of client"
  },
  {
    "field": "client_tax_id",
    "type": "string",
    "sensitive": true,
    "constraints": "Part of client"
  },
  {
    "field": "payment_details",
    "type": "object",
    "sensitive": false,
    "constraints": "Payment methods"
  },
  {
    "field": "iban",
    "type": "string",
    "sensitive": true,
    "constraints": "Part of payment_details"
  },
  {
    "field": "items",
    "type": "array",
    "sensitive": false,
    "constraints": "List of purchased goods"
  },
  {
    "field": "item_id",
    "type": "integer",
    "sensitive": false,
    "constraints": "Sequential index"
  },
  {
    "field": "description",
    "type": "string",
    "sensitive": false,
    "constraints": "Product details"
  },
  {
    "field": "quantity",
    "type": "number",
    "sensitive": false,
    "constraints": "Must be > 0"
  },
  {
    "field": "unit_measure",
    "type": "string",
    "sensitive": false,
    "constraints": "e.g., 'each'"
  },
  {
    "field": "net_price",
    "type": "number",
    "sensitive": false,
    "constraints": "Price per unit"
  },
  {
    "field": "net_worth",
    "type": "number",
    "sensitive": false,
    "constraints": "quantity * net_price"
  },
  {
    "field": "vat_rate",
    "type": "percentage",
    "sensitive": false,
    "constraints": "Tax percentage"
  },
  {
    "field": "gross_worth",
    "type": "number",
    "sensitive": false,
    "constraints": "net_worth * (1 + vat_rate)"
  },
  {
    "field": "summary",
    "type": "object",
    "sensitive": false,
    "constraints": "Totals calculation"
  },
  {
    "field": "total_net_worth",
    "type": "number",
    "sensitive": false,
    "constraints": "Sum of all items net_worth"
  },
  {
    "field": "total_vat",
    "type": "number",
    "sensitive": false,
    "constraints": "Sum of VAT amounts"
  },
  {
    "field": "total_gross_worth",
    "type": "number",
    "sensitive": false,
    "constraints": "total_net_worth + total_vat"
  }
]
